#include<bits/stdc++.h>
using namespace std;
const int N = 1e5;
const long long Mod = 998244353;
const int B = 131;
long long pw[N];//B[i]表示B的i次方
long long ss[N];
int main( )
{
    int n;
    cin >> n;
    pw[0] = 1;
    for(int i = 1; i < N; i++){
        pw[i] = pw[i - 1] * B;
    }
    for(int i = 0; i < n ; i++){
        string s;
        cin >> s;
        int a = 0;
        for(int j = 0; j < s.size(); j++){
            a += s[j] * pw[j] % Mod;
            a %= Mod;
        }
        ss[i] = a;
    }
    int ans = 0;
    for(int i = 0; i < n; i++){
        int f = 0;
        for(int j = i + 1; j < n; j++){
            if(ss[i] == ss[j])f = 1;
        }
        if(!f)ans++;
    }
    cout << ans;
}
